import NProgress from 'https://cdn.jsdelivr.net/npm/nprogress@0.2.0/+esm';
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/nprogress@0.2.0/nprogress.css'; document.head.appendChild(css);
NProgress.configure(data.configure ?? { showSpinner: true, trickleSpeed: 800 });
NProgress.start();            // 开始 trickle
